          Map<String, Object> esOrgMap = orgInfoMap.get(userOrg.get(JsonKey.ORGANISATION_ID));
          esOrgMap.remove(JsonKey.ID);
          userOrg.putAll(esOrgMap);
          userOrganisations.add(userOrg);

