		$wp_query->is_author            = true;
		$wp_query->query_vars['author'] = $this->teacher_user->ID;
		$wp_query->queried_object       = $this->teacher_user;
		$wp_query->queried_object_id    = $this->teacher_user->ID;

		// Setup $post to be the first lesson.
		$posts = get_posts(
			array_merge(
				$args,
				array(
					'posts_per_page' => 1,
				)
			)
		);
		$post  = $posts[0];

