get_renderer
		$show_pagination = $this->get_option( 'show_pagination', true );

		/**
		 * Whether to show pagination on the CPT page when displaying on a
		 * theme that does not explicitly support Sensei.
		 *
		 * @param  bool   $show_pagination The initial value.
		 * @param  string $post_type       The post type.
		 * @param  int    $post_id         The post ID.
		 * @return bool
		 */
		$show_pagination = apply_filters(
			'sensei_cpt_page_show_pagination',
			$show_pagination,
			$this->post_type,
			$this->post_id
		);

		return new Sensei_Renderer_Single_Post(
			$this->post_id,
			$this->get_template_filename(),
			array(
				'show_pagination' => $show_pagination,
			)
		);

testHandleCourseLessonsWithModules
		$course_id        = $this->factory->course->create();
		$lessons          = $this->factory->lesson->create_many( 6 );
		$module_a_lessons = [
			'232'  => $lessons[1],
			'4255' => $lessons[3],
		];
		$module_b_lessons = [
			'122' => $lessons[2],
			'44'  => $lessons[4],
		];
		$loose_lessons    = [
			'425' => $lessons[5],
			'306' => $lessons[0],
		];

		$all_lessons = $module_a_lessons + $module_b_lessons + $loose_lessons;

		$module_a   = Sensei_Data_Port_Utilities::get_term( 'Module A', 'module', 1 );
		$module_b   = Sensei_Data_Port_Utilities::get_term( 'Module B', 'module', 1 );
