                        coolTextBox1.Text = "'" + txt + "'";
                    else
                        coolTextBox1.Text = txt.Trim('\'');
                    break;
                case "( )":
                    if (!string.IsNullOrEmpty(txt) && txt[0] != '(' && txt[txt.Length - 1] != ')')
                        coolTextBox1.Text = "(" + txt + ")";
                    break;
                case "+":
                case "-":
                case "*":
                case "/":
                case "|":
                case "~":
                case "^":
                case ">":
                case "<":
                case "=":
                case "%":
                case "?":
                case "#":
                    coolTextBox1.Text = txt + sign;
                    break;
                case "&&":
                    coolTextBox1.Text = txt + "&";
                    break;
                case "T":
                    coolTextBox1.Text = txt + "True";
                    break;
                case "F":
                    coolTextBox1.Text = txt + "False";
                    break;

