                    return value.Word;
                case DataType.SHORT:
                    return value.Int16;
                case DataType.DWORD:
                    return value.DWord;
                case DataType.INT:
                    return value.Int32;
                case DataType.FLOAT:
                    return value.Single;
                case DataType.STR:
                    return tag.ToString();
                default:
                    return null;

public
            int len = frame.Length;
            byte[] chk = CalculateCrc(frame, len - 2);
            return (chk[0] == frame[len - 2] && chk[1] == frame[len - 1]);

public
            DataType type = tag.Address.VarType;
            if (type == DataType.BOOL) return value.Boolean ? 1f : 0f;
            IDataServer srv = tag.Parent.Server;
            int ind = srv.GetScaleByID(tag.ID);
            Scaling meta = ind < 0 ? Scaling.Empty : srv.ScalingList[ind];
            if (meta.ScaleType == ScaleType.None)
            {
                switch (type)
                {
                    case DataType.BYTE:
                        return value.Byte;
                    case DataType.WORD:
                        return value.Word;
                    case DataType.SHORT:
                        return value.Int16;
                    case DataType.DWORD:
                        return value.DWord;
                    case DataType.INT:
                        return value.Int32;
                    case DataType.FLOAT:
                        return value.Single;
                    case DataType.STR:
                        return float.Parse(tag.ToString());
                    default:
                        return 0f;

public
            Storage value = Storage.Empty;
            var str = obj as string;
            switch (tag.Address.VarType)
            {
                case DataType.BOOL:
                    value.Boolean = str == null ? Convert.ToBoolean(obj) : str == "0" ? false : str == "1" ? true : bool.Parse(str);
                    break;
                case DataType.BYTE:
                    value.Byte = Convert.ToByte(obj);
                    break;
                case DataType.WORD:
                    value.Word = Convert.ToUInt16(obj);
                    break;
                case DataType.SHORT:
                    value.Int16 = Convert.ToInt16(obj);
                    break;
                case DataType.DWORD:
                    value.DWord = Convert.ToUInt32(obj);
                    break;
                case DataType.INT:
                    value.Int32 = Convert.ToInt32(obj);
                    break;
                case DataType.FLOAT:
                    value.Single = Convert.ToSingle(obj);
                    break;

